const input = $input.first().json;
const action = input.action || 'search_station';
const BASE = 'https://transport.opendata.ch/v1';
const HEADERS = { 'Accept': 'application/json', 'User-Agent': 'n8n-claw-sbb/1.0' };

async function apiGet(path) {
  return await helpers.httpRequest({
    method: 'GET',
    url: BASE + path,
    headers: HEADERS,
    timeout: 20000
  });
}

function fmtTime(iso) {
  if (!iso) return '?';
  return iso.substring(11, 16);
}

// SBB delay is in MINUTES (not seconds like db-rest)
function fmtDelay(delayMin) {
  if (!delayMin && delayMin !== 0) return '';
  const m = parseInt(delayMin);
  if (isNaN(m) || m <= 0) return '';
  return ' +' + m + 'min';
}

// Parse SBB duration format "00d00:56:00" -> "56min" / "1h4min"
function parseSbbDuration(str) {
  if (!str) return '?';
  const m = /^(\d+)d(\d+):(\d+):(\d+)$/.exec(str);
  if (!m) return str;
  const days = parseInt(m[1]);
  const hours = parseInt(m[2]);
  const mins = parseInt(m[3]);
  const totalH = days * 24 + hours;
  if (totalH > 0) return totalH + 'h' + (mins > 0 ? mins + 'min' : '');
  return mins + 'min';
}

function platformStr(p) {
  return p || '?';
}

// === search_station ===
if (action === 'search_station') {
  const query = input.query;
  if (!query) return [{ json: { error: 'Parameter "query" is required.' } }];

  try {
    const res = await apiGet('/locations?query=' + encodeURIComponent(query) + '&type=station');
    const stations = res.stations || [];
    if (stations.length === 0) {
      return [{ json: { result: 'No stations found for: ' + query } }];
    }
    let result = 'Stations for "' + query + '":\n\n';
    for (const s of stations.slice(0, 5)) {
      result += '- ' + s.name + ' (ID: ' + s.id + ')';
      if (s.icon) result += ' [' + s.icon + ']';
      result += '\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Station search failed: ' + err.message } }];
  }

// === get_departures ===
} else if (action === 'get_departures') {
  const station = input.station;
  if (!station) return [{ json: { error: 'Parameter "station" is required (name or ID).' } }];

  try {
    const limit = parseInt(input.results) || 10;
    const url = '/stationboard?station=' + encodeURIComponent(station) + '&limit=' + limit + '&type=departure';
    const res = await apiGet(url);
    const board = res.stationboard || [];
    if (board.length === 0) {
      return [{ json: { result: 'No departures found.' } }];
    }

    const stName = res.station?.name || station;
    let result = 'Departures from ' + stName + ':\n\n';
    for (const e of board) {
      const time = fmtTime(e.stop?.departure);
      const delay = fmtDelay(e.stop?.delay);
      const cat = e.category || '';
      const num = e.number || '';
      const line = e.name || (cat + num) || '?';
      const dir = e.to || '?';
      const pl = platformStr(e.stop?.platform);
      result += time + delay + ' | ' + line + ' → ' + dir + ' | Gl.' + pl + '\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Departures failed: ' + err.message } }];
  }

// === get_arrivals ===
} else if (action === 'get_arrivals') {
  const station = input.station;
  if (!station) return [{ json: { error: 'Parameter "station" is required (name or ID).' } }];

  try {
    const limit = parseInt(input.results) || 10;
    const url = '/stationboard?station=' + encodeURIComponent(station) + '&limit=' + limit + '&type=arrival';
    const res = await apiGet(url);
    const board = res.stationboard || [];
    if (board.length === 0) {
      return [{ json: { result: 'No arrivals found.' } }];
    }

    const stName = res.station?.name || station;
    let result = 'Arrivals at ' + stName + ':\n\n';
    for (const e of board) {
      const time = fmtTime(e.stop?.arrival || e.stop?.departure);
      const delay = fmtDelay(e.stop?.delay);
      const cat = e.category || '';
      const num = e.number || '';
      const line = e.name || (cat + num) || '?';
      // SBB has no 'provenance' field → use first passList entry as origin
      let from = '?';
      if (Array.isArray(e.passList) && e.passList.length > 0) {
        from = e.passList[0].station?.name || '?';
      }
      const pl = platformStr(e.stop?.platform);
      result += time + delay + ' | ' + line + ' from ' + from + ' | Gl.' + pl + '\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Arrivals failed: ' + err.message } }];
  }

// === search_journey ===
} else if (action === 'search_journey') {
  const from = input.from;
  const to = input.to;
  if (!from || !to) return [{ json: { error: 'Parameters "from" and "to" are required (station name or ID).' } }];

  try {
    const results = parseInt(input.results) || 3;
    let url = '/connections?from=' + encodeURIComponent(from) + '&to=' + encodeURIComponent(to) + '&limit=' + results;
    if (input.departure) {
      const d = new Date(input.departure);
      if (!isNaN(d.getTime())) {
        url += '&date=' + d.toISOString().slice(0, 10);
        url += '&time=' + d.toISOString().slice(11, 16);
      }
    }

    const res = await apiGet(url);
    const connections = res.connections || [];
    if (connections.length === 0) {
      return [{ json: { result: 'No connections found.' } }];
    }

    let result = 'Connections ' + from + ' → ' + to + ':\n\n';
    for (let i = 0; i < connections.length; i++) {
      const c = connections[i];
      const dep = fmtTime(c.from?.departure);
      const arr = fmtTime(c.to?.arrival);
      const depDelay = fmtDelay(c.from?.delay);
      const dur = parseSbbDuration(c.duration);
      const transfers = c.transfers || 0;

      result += (i + 1) + ') ' + dep + depDelay + ' → ' + arr + ' | ' + dur;
      if (transfers > 0) result += ' | ' + transfers + 'x umsteigen';
      result += '\n';

      const sections = c.sections || [];
      for (const s of sections) {
        if (s.walk) {
          result += '   🚶 Walk';
          if (s.walk.duration) result += ' (' + Math.round(s.walk.duration / 60) + 'min)';
          result += '\n';
          continue;
        }
        if (!s.journey) continue;
        const lDep = fmtTime(s.departure?.departure);
        const lArr = fmtTime(s.arrival?.arrival);
        const lDelay = fmtDelay(s.departure?.delay);
        const jCat = s.journey.category || '';
        const jNum = s.journey.number || '';
        const line = s.journey.name || (jCat + jNum) || '?';
        const orig = s.departure?.station?.name || '?';
        const dest = s.arrival?.station?.name || '?';
        const plDep = platformStr(s.departure?.platform);
        const plArr = platformStr(s.arrival?.platform);
        result += '   ' + lDep + lDelay + ' ' + orig + ' Gl.' + plDep + ' → ' + lArr + ' ' + dest + ' Gl.' + plArr + ' | ' + line + '\n';
      }
      result += '\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Journey search failed: ' + err.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: ' + action + '. Use search_station, get_departures, get_arrivals, or search_journey.' } }];
}
